#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int jump(vector<int>& nums) {
        int n = nums.size();
        if (n <= 1) return 0;
        int max_reach = nums[0];
        int step = nums[0];
        int jumps = 1;
        for (int i = 1; i < n; i++) {
            if (i == n - 1) return jumps;
            max_reach = max(max_reach, i + nums[i]);
            step--;
            if (step == 0) {
                jumps++;
                if (i >= max_reach) return -1;
                step = max_reach - i;
            }
        }
        return jumps;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    Solution sol;
    int ans = sol.jump(nums);
    cout << ans << "\n";
    return 0;
}
